python -c "
import outlines
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', lambda x: x.upper() + '!')

@outlines.prompt
def greet(name):
    'Hello {{ name | shout }}'

print(greet('world'))

unregister_filter('shout')
try:
    greet2 = outlines.prompt(lambda name: None)
except Exception:
    pass

@outlines.prompt
def greet2(name):
    'Hello {{ name }}'
print(greet2('world'))

try:
    @outlines.prompt
    def bad(name):
        'Hello {{ name | shout }}'
    bad('world')
    print('ERROR: should have raised')
except Exception as e:
    print('correctly raised:', type(e).__name__)
"

